import pytest
import requests

def test_create_observation_with_loinc_code_returns_201(auth_headers, patient_id, base_url):
    payload = {
        "resourceType": "Observation",
        "status": "final",
        "code": {
            "coding": [
                {
                    "system": "http://loinc.org",
                    "code": "8867-4",
                    "display": "Heart rate"
                }
            ]
        },
        "subject": {"reference": f"Patient/{patient_id}"},
        "valueQuantity": {"value": 72, "unit": "bpm", "system": "http://unitsofmeasure.org", "code": "/min"}
    }
    resp = requests.post(f"{base_url}/Observation", json=payload, headers=auth_headers)
    assert resp.status_code == 201, f"Expected 201, got {resp.status_code}: {resp.text}"
    body = resp.json()
    assert body.get("resourceType") == "Observation"
    assert body.get("id"), "Server must assign an id"
    codes = [c["code"] for c in body["code"]["coding"]]
    assert "8867-4" in codes

import pytest
import requests

@pytest.mark.parametrize("label,code_field,expected_status", [
    (
        "valid_loinc",
        {"coding": [{"system": "http://loinc.org", "code": "55284-4", "display": "BP"}]},
        201
    ),
    (
        "empty_coding_list",
        {"coding": []},
        422
    ),
    (
        "null_code",
        None,
        422
    ),
])
def test_observation_code_present_vs_absent_decision_table(
    label, code_field, expected_status, auth_headers, patient_id, base_url
):
    payload = {
        "resourceType": "Observation",
        "status": "final",
        "subject": {"reference": f"Patient/{patient_id}"}
    }
    if code_field is not None:
        payload["code"] = code_field
    # null code: omit key entirely to test missing-field path
    resp = requests.post(f"{base_url}/Observation", json=payload, headers=auth_headers)
    assert resp.status_code == expected_status, (
        f"[{label}] Expected {expected_status}, got {resp.status_code}: {resp.text}"
    )
